import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as s,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"en/Safety/webdav-site-access.md","filePath":"en/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),d={name:"en/Safety/webdav-site-access.md"};function l(r,e,c,h,p,u){return s(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>The WebDAV setting in Security Settings exposes your ImgBed site as a WebDAV endpoint.</p><p>After it is enabled, you can use Windows, macOS, mobile file managers, or any WebDAV-compatible client to browse, upload, delete, and manage ImgBed files like a remote folder.</p><p>This is the site&#39;s WebDAV access entry. It is different from the WebDAV storage channel in Upload Settings. The upload channel stores files in a third-party WebDAV service. This setting lets your ImgBed site provide WebDAV access to clients.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open the admin panel, then go to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="what-this-feature-does" tabindex="-1">What This Feature Does <a class="header-anchor" href="#what-this-feature-does" aria-label="Permalink to &quot;What This Feature Does&quot;">​</a></h2><p>After WebDAV is enabled, ImgBed provides a fixed access URL:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Use this URL to connect to your ImgBed file directory.</p><p>Good use cases:</p><ul><li>Browse ImgBed files directly from your computer file manager.</li><li>Drag images into the WebDAV folder to upload them.</li><li>Organize ImgBed folders from your local file manager.</li><li>Use WebDAV-compatible software to sync or manage images.</li><li>Access ImgBed content without opening the admin panel.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Turns the WebDAV endpoint on.</p><p>When disabled, clients cannot connect through WebDAV.</p><h3 id="username-and-password" tabindex="-1">Username and Password <a class="header-anchor" href="#username-and-password" aria-label="Permalink to &quot;Username and Password&quot;">​</a></h3><p>These credentials are used by WebDAV clients when connecting.</p><p>Use a dedicated WebDAV username and password. Do not reuse the admin password or upload password.</p><p>If either username or password is empty, WebDAV clients cannot connect properly.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode decides which image URL WebDAV clients prefer when reading images.</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed chooses based on context. Recommended for normal use.</td></tr><tr><td>Original</td><td>Prefer original images.</td></tr><tr><td>Thumbnail</td><td>Prefer thumbnails. Useful for fast preview.</td></tr></tbody></table><p>If you are unsure, keep <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>The default channel is used for WebDAV uploads.</p><p>When you copy files into the WebDAV directory from Windows or another client, ImgBed uploads them through the selected default upload channel.</p><p>If no default channel is selected, browsing may work, but uploads may fail.</p><h2 id="accessing-webdav-in-windows-11" tabindex="-1">Accessing WebDAV in Windows 11 <a class="header-anchor" href="#accessing-webdav-in-windows-11" aria-label="Permalink to &quot;Accessing WebDAV in Windows 11&quot;">​</a></h2><p>Windows 11 can add WebDAV as a network location.</p><ol><li>Open <code>This PC</code>.</li><li>Choose <code>Add a network location</code>.</li><li>Enter <code>https://your-domain.com/dav</code>.</li><li>Enter your WebDAV username and password when prompted.</li><li>Finish the wizard. The WebDAV directory can then be opened in File Explorer.</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>After it is added, the WebDAV directory appears in Windows File Explorer. You can open, copy, and manage files like a normal folder.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>After a successful WebDAV connection, you can usually:</p><ul><li>View files and folders.</li><li>Upload files.</li><li>Create folders.</li><li>Rename files or folders.</li><li>Move files.</li><li>Delete files.</li></ul><p>WebDAV is best for everyday access and small-scale file management. For large moves, bulk deletes, or complex organization, use the admin panel.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>Successful WebDAV connections also appear under the WebDAV tab in Login Device Management.</p><p>You can review WebDAV clients there and force old devices offline when needed.</p><p>If you change the WebDAV username or password, old clients need to sign in again.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-keeps-asking-for-username-and-password" tabindex="-1">Windows Keeps Asking for Username and Password <a class="header-anchor" href="#windows-keeps-asking-for-username-and-password" aria-label="Permalink to &quot;Windows Keeps Asking for Username and Password&quot;">​</a></h3><p>Check:</p><ul><li>The URL is <code>https://your-domain.com/dav</code>.</li><li>The username and password match the WebDAV settings.</li><li>WebDAV is enabled.</li><li>The site can be accessed over HTTPS.</li></ul><h3 id="browsing-works-but-uploading-fails" tabindex="-1">Browsing Works, but Uploading Fails <a class="header-anchor" href="#browsing-works-but-uploading-fails" aria-label="Permalink to &quot;Browsing Works, but Uploading Fails&quot;">​</a></h3><p>Check the <code>Default channel</code>.</p><p>WebDAV uploads need a default upload channel. If it is missing, disabled, or misconfigured, uploads may fail.</p><h3 id="access-speed-is-unstable" tabindex="-1">Access Speed Is Unstable <a class="header-anchor" href="#access-speed-is-unstable" aria-label="Permalink to &quot;Access Speed Is Unstable&quot;">​</a></h3><p>WebDAV performance depends on the client, network, file count, and default upload channel.</p><p>If a directory has many files, organize them into folders instead of keeping too many files in one directory.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>Use HTTPS for WebDAV access.</li><li>Set a strong password.</li><li>Do not share the WebDAV password with untrusted people.</li><li>Turn WebDAV off when you do not use it.</li><li>Periodically clean up unused WebDAV devices in Login Device Management.</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients do not use the browser upload page&#39;s large-file chunking flow. For files above the suggested limits below, use the web upload page instead.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(d,[["render",l]]);export{m as __pageData,f as default};
